fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let mut edges = edges;
    edges.sort_by(|a, b| a[2].cmp(&b[2]));

    let mut parent: Vec<i64> = (0..n).map(|x| x as i64).collect();
    let mut rank: Vec<i64> = vec![1; n as usize];

    fn find(parent: &mut Vec<i64>, u: i64) -> i64 {
        while parent[u as usize] != u {
            parent[u as usize] = parent[parent[u as usize] as usize];
            u = parent[u as usize];
        }
        u
    }

    fn union(parent: &mut Vec<i64>, rank: &mut Vec<i64>, u: i64, v: i64) -> bool {
        let u_root = find(parent, u);
        let v_root = find(parent, v);
        if u_root == v_root {
            return false;
        }
        if rank[u_root as usize] < rank[v_root as usize] {
            parent[u_root as usize] = v_root;
            rank[v_root as usize] += rank[u_root as usize];
        } else {
            parent[v_root as usize] = u_root;
            rank[u_root as usize] += rank[v_root as usize];
        }
        true
    }

    let mut components = n;
    for edge in edges {
        let u = edge[0];
        let v = edge[1];
        let time = edge[2];
        if union(&mut parent, &mut rank, u, v) {
            components -= 1;
        }
        if components >= k {
            return time;
        }
    }
    0
}
